{"command": "cat > /tmp/test_copy_cb_kwargs.py << 'EOF'
"""Test that copy creates independent cb_kwargs"""
from scrapy.http import Request


def test_request_copy_cb_kwargs_independence():
    """Test that copying preserves independence of cb_kwargs"""
    original_dict = {"arg": "value"}
    request1 = Request("http://example.com", cb_kwargs=original_dict)

    # Verify request1 has the arg
    assert request1.cb_kwargs == {"arg": "value"}

    # Create a copy
    request2 = request1.copy()

    # Both should have the same content
    assert request1.cb_kwargs == request2.cb_kwargs == {"arg": "value"}

    # They should be different objects
    assert request1.cb_kwargs is not request2.cb_kwargs

    # Modify original_dict
    original_dict["new_key"] = "new_value"

    # Neither request should be affected
    assert request1.cb_kwargs == {"arg": "value"}
    assert request2.cb_kwargs == {"arg": "value"}

    # Modify request1's cb_kwargs
    request1.cb_kwargs["another_key"] = "another_value"

    # request2 should not be affected
    assert request2.cb_kwargs == {"arg": "value"}

    print("✓ Test passed: Copy creates independent cb_kwargs dicts")


if __name__ == "__main__":
    test_request_copy_cb_kwargs_independence()
